#include <iostream>
#include <cassert>
#include <cmath>
using namespace std;

double calculateArea(double sideLength);
double calculateArea(double length, double width);

int main() {
    assert(abs(calculateArea(5.0, 3.0) - 15.0) < 0.001);
    assert(abs(calculateArea(4.5, 2.0) - 9.0) < 0.001);
    assert(abs(calculateArea(10.0, 7.5) - 75.0) < 0.001);
    assert(abs(calculateArea(0.0, 5.0) - 0.0) < 0.001);
    assert(abs(calculateArea(3.2, 4.8) - 15.36) < 0.001);
    cout << "All tests passed!" << endl;
    return 0;
}
